function norm(value) {
  return String(value || '').trim().toLowerCase();
}
function canApprove(role) {
  return ['owner', 'approver', 'approve'].includes(norm(role));
}
const request = $node['POST /admin-approve'].json;
const body = request.body || request;
const adminUid = String(body.adminUid || '').trim();
if (!adminUid) throw new Error('Missing adminUid. Please open approve page in LINE LIFF and login as admin.');
const admin = $input.all().map(item => item.json)
  .find(row => String(row.LINE_UID || row.lineUid || '').trim() === adminUid);
if (!admin) throw new Error('This LINE user is not listed in Admins sheet: ' + adminUid);
if (norm(admin.Status) !== 'active') throw new Error('This admin is inactive: ' + (admin.Display_Name || adminUid));
if (!canApprove(admin.Role)) throw new Error('This admin role cannot approve orders: ' + (admin.Role || ''));
return [{ json: { ...body, adminUid, authorizedAdmin: admin } }];

function parseJson(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}
function text(value) { return String(value ?? '').trim(); }
function number(value, label, { min = 0, integer = false } = {}) {
  const result = Number(value);
  if (!Number.isFinite(result) || result < min || (integer && !Number.isInteger(result))) {
    throw new Error(label + ' is invalid');
  }
  return result;
}

const authorized = $node['Authorize Admin Approval'].json;
const requestedOrderId = text(authorized.orderId);
if (!requestedOrderId) throw new Error('Missing orderId');

const row = $input.all().map(item => item.json)
  .find(item => text(item.Order_ID) === requestedOrderId);
if (!row) throw new Error('Order not found: ' + requestedOrderId);

const status = text(row.Status || 'Pending').toLowerCase();
if (status !== 'pending') {
  const approvedBy = text(row.Approved_By);
  const approvedAt = text(row.Approved_At);
  throw new Error('Order is no longer pending (status: ' + (row.Status || '-') + ')' +
    (approvedBy ? ', approved by ' + approvedBy : '') +
    (approvedAt ? ' at ' + approvedAt : ''));
}

const details = parseJson(row.Order_Details, {});
const storedItems = Array.isArray(details.orderItems) ? details.orderItems : [];
if (!storedItems.length) throw new Error('The stored order has no items');

const sourceItems = Array.isArray(authorized.adjustedOrderItems) ? authorized.adjustedOrderItems : [];
if (sourceItems.length !== storedItems.length) throw new Error('Adjusted item count does not match the stored order');

const submittedById = new Map();
for (const item of sourceItems) {
  const id = text(item.productId || item.Product_ID);
  if (!id || submittedById.has(id)) throw new Error('Adjusted items contain a missing or duplicate product ID');
  submittedById.set(id, item);
}

const adjustedOrderItems = storedItems.map((stored) => {
  const productId = text(stored.productId || stored.Product_ID);
  const submitted = submittedById.get(productId);
  if (!submitted) throw new Error('Adjusted items do not match the stored order');
  const originalQuantity = number(stored.originalQuantity ?? stored.quantity ?? stored.Quantity, 'Stored quantity for ' + productId, { integer: true });
  const quantity = number(submitted.quantity, 'Approved quantity for ' + productId, { integer: true });
  if (quantity > originalQuantity) throw new Error('Approved quantity exceeds ordered quantity for ' + productId);
  const pricePerUnit = number(stored.pricePerUnit ?? stored.Price ?? stored.price, 'Stored price for ' + productId);
  return {
    productId,
    productName: text(stored.productName || stored.Product_Name || stored.name),
    unit: text(stored.unit || stored.Unit),
    originalQuantity,
    quantity,
    pricePerUnit,
    lineTotal: Number((quantity * pricePerUnit).toFixed(2)),
  };
});

const hasReduction = adjustedOrderItems.some(item => item.quantity < item.originalQuantity);
const adjustmentReason = text(authorized.adjustmentReason);
if (hasReduction && !adjustmentReason) throw new Error('Adjustment reason is required when reducing quantities');

const subtotal = Number(adjustedOrderItems.reduce((sum, item) => sum + item.lineTotal, 0).toFixed(2));
const shippingCost = number(authorized.shippingCost || 0, 'Shipping cost');
const discount = number(authorized.discount || 0, 'Discount');
const otherFee = number(authorized.otherFee || 0, 'Other fee');
if (discount > subtotal) throw new Error('Discount cannot exceed the adjusted subtotal');

return [{ json: {
  ...authorized,
  orderId: row.Order_ID,
  branchUid: text(row.LINE_UID),
  branchDisplayName: text(details.displayName || row.LINE_UID),
  orderDetails: details,
  orderNote: text(details.note),
  approvalHistory: parseJson(row.Approval_History, []),
  adjustedOrderItems,
  adjustmentReason,
  shippingCost,
  discount,
  otherFee,
  approvedAt: new Date().toISOString(),
} }];

const body = $json.body || $json;
const items = Array.isArray(body.adjustedOrderItems) ? body.adjustedOrderItems : [];
if (!items.length) throw new Error('No validated order items to approve');
const subtotal = Number(items.reduce((sum, item) => sum + Number(item.lineTotal || 0), 0).toFixed(2));
const shippingCost = Number(body.shippingCost || 0);
const discount = Number(body.discount || 0);
const otherFee = Number(body.otherFee || 0);
const amountBeforeVat = Math.max(0, subtotal - discount);
const vatAmount = Number((amountBeforeVat * 0.07).toFixed(2));
const totalAmount = Number((amountBeforeVat + vatAmount + shippingCost + otherFee).toFixed(2));
const admin = body.authorizedAdmin || {};
const approvedAt = body.approvedAt || new Date().toISOString();
const adminUid = body.adminUid || '';
const adminName = admin.Display_Name || admin.Admin_ID || adminUid;
const previous = Array.isArray(body.approvalHistory) ? body.approvalHistory : [];
const history = [...previous, {
  action: 'APPROVED', adminUid, adminName, adminRole: admin.Role || '', approvedAt,
  adjustmentReason: body.adjustmentReason || '', adminNote: body.adminNote || '',
  items: items.map(item => ({ productId: item.productId, originalQuantity: item.originalQuantity, approvedQuantity: item.quantity })),
}];
const originalDetails = body.orderDetails && typeof body.orderDetails === 'object' ? body.orderDetails : {};
return [{ json: {
  Order_ID: body.orderId, Branch_UID: body.branchUid || '',
  Order_Details: JSON.stringify({ ...originalDetails, orderItems: items, note: body.orderNote || '' }),
  Subtotal: subtotal, Shipping_Cost: shippingCost, Discount: discount, Other_Fee: otherFee,
  VAT_Amount: vatAmount, Total_Amount: totalAmount, Status: 'Approved', Credit_Terms_Days: 7,
  Credit_Due_Date: new Date(new Date(approvedAt).getTime() + 7 * 86400000).toISOString(),
  Payment_Status: 'Credit Pending', Admin_Note: body.adminNote || '', Adjustment_Reason: body.adjustmentReason || '',
  Approved_By_UID: adminUid, Approved_By: adminName, Approved_At: approvedAt, Approval_History: JSON.stringify(history),
} }];

const a = $node['Build Approval Row'].json;
const p = $node['Aggregate Delivery Tax Invoice PDFs'].json;
const n = $node['Summarize Admin Approval Notify'].json;
return [{ json: {
  success: true, orderId: a.Order_ID, status: a.Status, subtotal: a.Subtotal,
  shippingCost: a.Shipping_Cost, discount: a.Discount, otherFee: a.Other_Fee,
  vatAmount: a.VAT_Amount, totalAmount: a.Total_Amount, adjustmentReason: a.Adjustment_Reason,
  approvalHistory: JSON.parse(a.Approval_History || '[]'), pdfUrl: p.pdfUrl, pdfUrls: p.pdfUrls,
  pageCount: p.pageCount, adminNotification: n,
} }];

function parseJson(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}
function pickFirst(source, keys, fallback = '') {
  for (const key of keys) {
    const value = source?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return fallback;
}
function formatThaiDate(value) {
  const date = value ? new Date(value) : new Date();
  const validDate = Number.isNaN(date.getTime()) ? new Date() : date;
  const parts = new Intl.DateTimeFormat('en-GB', { timeZone: 'Asia/Bangkok', day: '2-digit', month: '2-digit', year: 'numeric' })
    .formatToParts(validDate).reduce((result, part) => { result[part.type] = part.value; return result; }, {});
  return parts.day + '/' + parts.month + '/' + parts.year;
}
const approval = $node['Build Approval Row'].json;
const rows = $input.all().map(item => item.json);
const row = rows.find(item => String(item.Order_ID || '').trim() === String(approval.Order_ID || '').trim());
if (!row) throw new Error('Order not found for Delivery Tax Invoice: ' + approval.Order_ID);
const delivery = parseJson(row.Delivery_Address, {});
const details = parseJson(row.Order_Details, {});
const allItems = Array.isArray(details.orderItems) ? details.orderItems : [];
const items = allItems.filter((item) => Number(pickFirst(item, ['quantity', 'Quantity', 'qty'], 0)) > 0);
const buyerName = pickFirst(details, ['buyerName', 'displayName', 'contactName'], pickFirst(row, ['Display_Name'], ''));
const branchName = pickFirst(delivery, ['label', 'Address_Label', 'branchName'], pickFirst(details, ['branchName'], ''));
const addressText = pickFirst(delivery, ['text', 'address', 'Address'], '');
const contactName = pickFirst(delivery, ['contactName', 'contact', 'Contact_Name'], pickFirst(details, ['contactName'], buyerName));
const contactTel = String(pickFirst(delivery, ['tel', 'Tel', 'TEL', 'phone', 'Phone', 'mobile'], pickFirst(row, ['Tel', 'Phone'], ''))).trim();
const approvedDate = formatThaiDate(approval.Approved_At || row.Approved_At || row.Timestamp);
const creditDueDate = formatThaiDate(approval.Credit_Due_Date || row.Credit_Due_Date || new Date(new Date(approval.Approved_At || row.Approved_At || row.Timestamp).getTime() + 7 * 86400000));
const subtotal = Number(approval.Subtotal ?? row.Subtotal ?? items.reduce((sum,item)=>sum+Number(item.lineTotal||0),0));
const shippingCost = Number(approval.Shipping_Cost || 0);
const discount = Number(approval.Discount || 0);
const otherFee = Number(approval.Other_Fee || 0);
const amountBeforeVat = Math.max(0, subtotal - discount);
const vatAmount = Number((amountBeforeVat * 0.07).toFixed(2));
const totalAmount = Number((amountBeforeVat + vatAmount + shippingCost + otherFee).toFixed(2));
const noteParts = [details.note || '', approval.Adjustment_Reason ? ('เน€เธซเธ•เธธเธเธฅเธเธฒเธฃเธเธฃเธฑเธเธเธณเธเธงเธ: ' + approval.Adjustment_Reason) : '', approval.Admin_Note ? ('เธซเธกเธฒเธขเน€เธซเธ•เธธ Admin: ' + approval.Admin_Note) : ''].filter(Boolean);
const pageSize = 20;
const pageCount = Math.max(1, Math.ceil(items.length / pageSize));
return Array.from({ length: pageCount }, (_, pageIndex) => {
  const pageNumber = pageIndex + 1;
  const pageItems = items.slice(pageIndex * pageSize, pageNumber * pageSize);
  const paddedItems = Array.from({ length: pageSize }, (_, index) => pageItems[index] || null);
  const documentNumber = pageCount > 1 ? (approval.Order_ID + ' (' + pageNumber + '/' + pageCount + ')') : approval.Order_ID;
  const values = [
    { range: 'Delivery Tax Invoice!D14', values: [[buyerName]] },
    { range: 'Delivery Tax Invoice!D15', values: [[branchName]] },
    { range: 'Delivery Tax Invoice!D16', values: [[addressText]] },
    { range: 'Delivery Tax Invoice!D17', values: [[contactName]] },
    { range: 'Delivery Tax Invoice!G17', values: [[contactTel ? ('Tel. ' + contactTel) : 'Tel.']] },
    { range: 'Delivery Tax Invoice!J14', values: [[documentNumber]] },
    { range: 'Delivery Tax Invoice!J15', values: [[approvedDate]] },
    { range: 'Delivery Tax Invoice!D18', values: [[noteParts.join(' | ')]] },
    { range: 'Delivery Tax Invoice!B22:B41', values: paddedItems.map((item, index) => [item ? pageIndex * pageSize + index + 1 : '']) },
    { range: 'Delivery Tax Invoice!C22:C41', values: paddedItems.map(item => [item ? pickFirst(item, ['productId', 'Product_ID', 'id']) : '']) },
    { range: 'Delivery Tax Invoice!E22:E41', values: paddedItems.map(item => [item ? pickFirst(item, ['productName', 'Product_Name', 'name']) : '']) },
    { range: 'Delivery Tax Invoice!G22:G41', values: paddedItems.map(item => [item ? Number(pickFirst(item, ['quantity', 'Quantity', 'qty'], 0)) : '']) },
    { range: 'Delivery Tax Invoice!H22:H41', values: paddedItems.map(item => [item ? pickFirst(item, ['unit', 'Unit', 'UOM']) : '']) },
    { range: 'Delivery Tax Invoice!I22:I41', values: paddedItems.map(item => [item ? Number(pickFirst(item, ['pricePerUnit', 'Price', 'price'], 0)) : '']) },
    { range: 'Delivery Tax Invoice!J22:J41', values: paddedItems.map(item => {
      if (!item) return [''];
      const quantity = Number(pickFirst(item, ['quantity', 'Quantity', 'qty'], 0));
      const price = Number(pickFirst(item, ['pricePerUnit', 'Price', 'price'], 0));
      return [Number(pickFirst(item, ['lineTotal', 'Line_Total', 'total'], quantity * price))];
    }) },
    { range: 'Delivery Tax Invoice!J46', values: [[subtotal]] },
    { range: 'Delivery Tax Invoice!J47', values: [[discount]] },
    { range: 'Delivery Tax Invoice!J48', values: [[amountBeforeVat]] },
    { range: 'Delivery Tax Invoice!J49', values: [[vatAmount]] },
    { range: 'Delivery Tax Invoice!J50', values: [[shippingCost + otherFee]] },
    { range: 'Delivery Tax Invoice!J52', values: [[totalAmount]] },
  ];
  const pageSuffix = pageCount > 1 ? ('-P' + String(pageNumber).padStart(2, '0') + '-of-' + String(pageCount).padStart(2, '0')) : '';
  return { json: {
    orderId: approval.Order_ID, branchUid: approval.Branch_UID || row.LINE_UID || '', branchName: branchName || buyerName || row.LINE_UID || '',
    subtotal, shippingCost, discount, otherFee, vatAmount, totalAmount, pageNumber, pageCount,
    fileName: 'DTI-' + approval.Order_ID + pageSuffix + '.pdf', copiedSheetName: 'DN_' + approval.Order_ID + pageSuffix,
    templateFileId: '1FYHjC9DjMpYJmc4fLo_sr6mOE-kKfp6OVQnrAqer8KY', folderId: '1IBbwvnGB157SfL-766gvHNQqIljH5sfa',
    valuesBatchUpdate: { valueInputOption: 'USER_ENTERED', data: values },
  } };
});

const payload = $('Build Delivery Tax Invoice Payload').item.json;
const copied = $json;
return { json: { ...payload, spreadsheetId: copied.id, copiedFileId: copied.id } };

const payload = $node['Merge Delivery Tax Invoice Template'].json;
const sheets = Array.isArray($json.sheets) ? $json.sheets : [];
const sheet = sheets.find(item => item.properties?.title === 'Delivery Tax Invoice') || sheets[0];
const sheetId = sheet?.properties?.sheetId;
if (!Number.isInteger(sheetId)) {
  throw new Error('Copied Delivery Tax Invoice spreadsheet does not contain a usable sheetId');
}
return [{ json: { ...payload, deliveryTaxInvoiceSheetId: sheetId } }];

const payload = $('Restore Delivery Tax Invoice Payload').item.json;
const upload = $json;
const pdfFileId = upload.id || payload.copiedFileId;
return { json: { ...payload, pdfFileId, pdfUrl: 'https://drive.google.com/file/d/' + pdfFileId + '/view?usp=drivesdk' }, binary: $binary };

const pages = $input.all().map(item => item.json).sort((a,b) => Number(a.pageNumber)-Number(b.pageNumber));
if (!pages.length) throw new Error('No Delivery Tax Invoice PDF was generated');
const first = pages[0];
return [{ json: { ...first, pageCount: pages.length, pdfFileIds: pages.map(page => page.pdfFileId), pdfUrls: pages.map(page => page.pdfUrl), pdfFileId: pages[0].pdfFileId, pdfUrl: pages[0].pdfUrl } }];

const payload = $node['Aggregate Delivery Tax Invoice PDFs'].json;
const money = (value) => Number(value || 0).toLocaleString('th-TH', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const links = payload.pdfUrls.map((url, index) => 'เอกสารหน้า ' + (index + 1) + ': ' + url).join('\n');
return [{ json: { to: payload.branchUid, text: [
  'คำสั่งซื้อได้รับการอนุมัติแล้ว',
  'เลขที่: ' + payload.orderId,
  'สาขา: ' + payload.branchName,
  'ยอดรวมสุทธิ: ฿' + money(payload.totalAmount),
  'ใบส่งของ/ใบกำกับภาษี PDF (' + payload.pageCount + ' หน้า):',
  links
].join('\n') } }];

function norm(value) { return String(value || '').trim().toLowerCase(); }
function asBool(value) { if (typeof value === 'boolean') return value; return ['true','1','yes','y'].includes(norm(value)); }
function money(value) { return Number(value || 0).toLocaleString('th-TH', { minimumFractionDigits: 2, maximumFractionDigits: 2 }); }
function parseJson(value, fallback) { try { return value ? JSON.parse(value) : fallback; } catch { return fallback; } }
const newline = String.fromCharCode(10);
const payload = $node['Aggregate Delivery Tax Invoice PDFs'].json;
const approval = $node['Build Approval Row'].json;
const details = parseJson(approval.Order_Details, {});
const items = Array.isArray(details.orderItems) ? details.orderItems : [];
const adjusted = items.filter(item => Number(item.originalQuantity ?? item.quantity ?? 0) !== Number(item.quantity || 0));
const adjustedLines = adjusted.slice(0, 10).map(item => '- ' + (item.productName || item.Product_Name || item.productId || item.Product_ID || '-') + ': ' + Number(item.originalQuantity || 0) + ' → ' + Number(item.quantity || 0));
const admins = $input.all().map(item => item.json);
const recipients = admins.filter(admin => { const uid = String(admin.LINE_UID || admin.lineUid || '').trim(); return uid && norm(admin.Status) === 'active' && asBool(admin.Notify_Order); });
if (recipients.length === 0) throw new Error('No ACTIVE admin with Notify_Order=TRUE for approval notification');
const approvedBy = approval.Approved_By || approval.Approved_By_UID || '-';
const pageLinks = payload.pdfUrls.map((url, index) => 'เอกสารหน้า ' + (index + 1) + ': ' + url).join(newline);
const lines = [
  'คำสั่งซื้อได้รับการอนุมัติแล้ว',
  'เลขที่: ' + payload.orderId,
  'สาขา: ' + payload.branchName,
  'ผู้อนุมัติ: ' + approvedBy,
  adjustedLines.length ? 'รายการที่ปรับจำนวน:' + newline + adjustedLines.join(newline) : 'รายการที่ปรับจำนวน: ไม่มี',
  approval.Adjustment_Reason ? 'เหตุผลการปรับ: ' + approval.Adjustment_Reason : '',
  'ยอดก่อนส่วนลด: ฿' + money(payload.subtotal),
  'ส่วนลด: ฿' + money(payload.discount),
  'VAT 7%: ฿' + money(payload.vatAmount),
  'ค่าขนส่ง: ฿' + money(payload.shippingCost),
  Number(payload.otherFee || 0) ? 'ค่าใช้จ่ายอื่น: ฿' + money(payload.otherFee) : '',
  'ยอดรวมสุทธิ: ฿' + money(payload.totalAmount),
  'เอกสารใบส่งของ/ใบกำกับภาษี PDF (' + payload.pageCount + ' หน้า):' + newline + pageLinks,
].filter(Boolean);
return recipients.map(admin => ({ json: { adminId: admin.Admin_ID || '', adminName: admin.Display_Name || '', to: String(admin.LINE_UID || admin.lineUid || '').trim(), text: lines.join(newline) } }));

const recipients = $items('Build Admin Approval LINE Message').map(item => item.json);
const outputs = $input.all().map(item => item.json || {});
const results = recipients.map((recipient, index) => {
  const output = outputs[index] || {};
  const error = output.error || output.message || '';
  return { adminId: recipient.adminId, adminName: recipient.adminName, to: recipient.to, success: !error && output.success !== false, error: error ? String(error) : '' };
});
return [{ json: { total: results.length, success: results.filter(item => item.success).length, failed: results.filter(item => !item.success).length, results } }];
